// CONFIGURATION
const DOSSIER_CIBLE = 'template rapport';

const response = $input.first().json;
const files = response.files || [];

if (files.length === 0) {
  return [{
    json: {
      success: false,
      timestamp: new Date().toISOString(),
      message: "Aucun fichier trouvé",
      contenu: []
    }
  }];
}

// Étape 1: Construire un index des dossiers (id -> nom)
const dossiersMap = {};
let dossierCibleId = null;
let dossierCibleNom = null;
const cibleLower = DOSSIER_CIBLE.toLowerCase().trim();

for (const file of files) {
  if (file.mimeType === 'application/vnd.google-apps.folder') {
    dossiersMap[file.id] = file.name;

    const nomLower = (file.name || '').toLowerCase().trim();
    if (nomLower === cibleLower || 
        nomLower === cibleLower.replace(/ /g, '_') ||
        nomLower === cibleLower.replace(/ /g, '')) {
      dossierCibleId = file.id;
      dossierCibleNom = file.name;
    }
  }
}

// Si dossier cible non trouvé
if (!dossierCibleId) {
  return [{
    json: {
      success: false,
      timestamp: new Date().toISOString(),
      message: `Dossier '${DOSSIER_CIBLE}' non trouvé`,
      dossierRecherche: DOSSIER_CIBLE,
      dossiersDisponibles: Object.values(dossiersMap).slice(0, 30),
      contenu: []
    }
  }];
}

// Étape 2: Filtrer les fichiers qui sont dans le dossier cible
const contenu = [];

for (const file of files) {
  const parents = file.parents || [];

  // Vérifier si ce fichier est dans le dossier cible
  if (parents.includes(dossierCibleId)) {
    // Trouver le nom du dossier parent
    const parentId = parents[0];
    const parentNom = dossiersMap[parentId] || 'Inconnu';

    contenu.push({
      fichier_id: file.id,
      fichier_nom: file.name,
      fichier_type: file.mimeType === 'application/vnd.google-apps.folder' ? 'dossier' : 'fichier',
      fichier_mimeType: file.mimeType,
      dossier_parent_id: parentId,
      dossier_parent_nom: parentNom
    });
  }
}

return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    dossierCible: {
      id: dossierCibleId,
      nom: dossierCibleNom
    },
    statistiques: {
      totalElements: contenu.length,
      sousDossiers: contenu.filter(e => e.fichier_type === 'dossier').length,
      fichiers: contenu.filter(e => e.fichier_type === 'fichier').length
    },
    contenu: contenu
  }
}];
